func TestMultiEnumField_ArrayAny(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	f, _ := reg.Lookup("application_platforms") // array/any
	expr, _, err := f.BuildSQL(mustJSON(search.MultiEnumFilter{Values: []string{"Common", "Coalition"}}), 1)
	if err != nil {
		t.Fatal(err)
	}
	if !strings.Contains(expr, "?|") {
		t.Errorf("expected ?| operator for array/any: %s", expr)
	}
}

