func TestSQLRefAs_BooleanCast(t *testing.T) {
	t.Parallel()
	src := search.FieldSource{
		Kind:      search.SourceJSONBPath,
		JSONBPath: []string{"some", "flag"},
		ValueType: search.JSONBBoolean,
	}
	ref := src.SQLRefAs("boolean")
	if !strings.Contains(ref, "::boolean") {
		t.Errorf("expected ::boolean cast: %s", ref)
	}
}

