		if !strings.Contains(errs[0].Message, "longitude") {
			t.Errorf("unexpected message: %q", errs[0].Message)
		}
	})

	t.Run("invalid state code", func(t *testing.T) {
		req := search.SearchRequest{
			UserLocation: &search.UserLocation{Latitude: 42.0, Longitude: -72.0, State: "m"},
		}
		errs := search.ValidateRequest(reg, req, true)
		if len(errs) != 1 {
			t.Fatalf("expected 1 error, got %d: %v", len(errs), errs)
		}
		if !strings.Contains(errs[0].Message, "2-letter uppercase") {
			t.Errorf("unexpected message: %q", errs[0].Message)
		}
	})

	t.Run("empty state is valid", func(t *testing.T) {
		req := search.SearchRequest{
			UserLocation: &search.UserLocation{Latitude: 42.0, Longitude: -72.0},
		}
		errs := search.ValidateRequest(reg, req, true)
		if len(errs) != 0 {
			t.Fatalf("expected no errors, got: %v", errs)
		}
