func TestBuildExportQuery(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	t.Run("caps limit to maxRows", func(t *testing.T) {
		req := search.SearchRequest{Limit: 1000}
		sql, args, err := search.BuildExportQuery(reg, req, 500)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "LIMIT") {
			t.Errorf("expected LIMIT in query: %s", sql)
		}
		// Last arg is the limit, should be capped to maxRows (500).
		limit := args[len(args)-1]
		if limit != 500 {
			t.Errorf("expected limit capped to 500, got %v", limit)
		}
	})

	t.Run("uses default limit when zero", func(t *testing.T) {
		req := search.SearchRequest{Limit: 0}
		_, args, err := search.BuildExportQuery(reg, req, 500)
		if err != nil {
			t.Fatal(err)
		}
		limit := args[len(args)-1]
		if limit != search.DefaultLimit {
			t.Errorf("expected default limit %d, got %v", search.DefaultLimit, limit)
		}
	})

	t.Run("positive limit within maxRows is preserved", func(t *testing.T) {
		req := search.SearchRequest{Limit: 50}
		_, args, err := search.BuildExportQuery(reg, req, 500)
		if err != nil {
			t.Fatal(err)
		}
		limit := args[len(args)-1]
		if limit != 50 {
			t.Errorf("expected limit 50, got %v", limit)
		}
	})
}

